#include <iostream>
#include <vector>
#include <memory>

class CustomAllocator {
public:
  using value_type = int;
  CustomAllocator() = default;
  int* allocate(std::size_t n) {
    std::cout << "Allocating " << n << " integers\n";
    return static_cast<int*>(::operator new(n * sizeof(int)));
  }
  void deallocate(int* p, std::size_t) {
    std::cout << "Deallocating memory\n";
    ::operator delete(p);
  }
};

int main() {
  std::vector<int, CustomAllocator> vec;
  vec.push_back(1);
  vec.push_back(2);
  std::cout << "Vector elements: " << vec[0] << ", " << vec[1] << "\n";
  return 0;
}
// Output:
// Allocating 1 integers
// Allocating 2 integers
// Vector elements: 1, 2
// Deallocating memory

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
  std::vector<int> vec = {5, 2, 9, 1, 5};
  for (auto it = vec.begin(); it != vec.end(); ++it) {
    std::cout << *it << " ";
  }
  std::cout << "\n";
  return 0;
}
// Output:
// 5 2 9 1 5

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
  std::vector<int> vec = {5, 2, 9, 1, 5};
  std::sort(vec.begin(), vec.end());
  for (int value : vec) {
    std::cout << value << " ";
  }
  std::cout << "\n";
  return 0;
}
// Output:
// 1 2 5 5 9

